DROP POLICY IF EXISTS "Zahlungsereignis sichtbar bei Auftragszugriff" ON public.auftrag_zahlungsereignisse; CREATE POLICY "Zahlungsereignis sichtbar bei Auftragszugriff" ON public.auftrag_zahlungsereignisse FOR SELECT TO authenticated USING (public.is_staff(auth.uid()) OR public.is_assigned_to_auftrag(auth.uid(), auftrag_id)); CREATE OR REPLACE FUNCTION public.create_zahlung(_auftrag_id uuid, _payment_type text, _betrag numeric, _datum timestamptz, _notiz text DEFAULT NULL, _positionen jsonb DEFAULT '[]'::jsonb, _leistungen jsonb DEFAULT '[]'::jsonb) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ DECLARE _ev_id uuid; _label text; _farbe text; BEGIN IF NOT (public.has_role(auth.uid(),'owner') OR public.has_permission(auth.uid(),'finanzen.manage')) THEN RAISE EXCEPTION 'Keine Berechtigung zum Erfassen von Zahlungen'; END IF; IF _payment_type NOT IN ('abbruch_bezahlt','teilweise_bezahlt','erledigt_bezahlt','sonstige_zahlung') THEN RAISE EXCEPTION 'Ungueltiger Zahlungstyp'; END IF; _label := CASE _payment_type WHEN 'abbruch_bezahlt' THEN 'Abbruch bezahlt' WHEN 'teilweise_bezahlt' THEN 'Teilweise bezahlt' WHEN 'erledigt_bezahlt' THEN 'Erledigt bezahlt' ELSE 'Sonstige Zahlung' END; _farbe := CASE _payment_type WHEN 'abbruch_bezahlt' THEN '#f59e0b' WHEN 'teilweise_bezahlt' THEN '#3b82f6' WHEN 'erledigt_bezahlt' THEN '#16a34a' ELSE '#64748b' END; INSERT INTO public.auftrag_zahlungsereignisse (auftrag_id, status_key, status_label, status_farbe, payment_type, datum, created_by, leistungen, notiz) VALUES (_auftrag_id, _payment_type, _label, _farbe, _payment_type, COALESCE(_datum, now()), auth.uid(), COALESCE(_leistungen, '[]'::jsonb), NULLIF(btrim(coalesce(_notiz,'')), '')) RETURNING id INTO _ev_id; INSERT INTO public.auftrag_zahlungsereignis_umsatz (ereignis_id, umsatz, positionen) VALUES (_ev_id, COALESCE(_betrag, 0), COALESCE(_positionen, '[]'::jsonb)); RETURN _ev_id; END; $fn$; GRANT EXECUTE ON FUNCTION public.create_zahlung(uuid, text, numeric, timestamptz, text, jsonb, jsonb) TO authenticated; CREATE OR REPLACE FUNCTION public.storno_zahlung(_ereignis_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $fn$ BEGIN IF NOT (public.has_role(auth.uid(),'owner') OR public.has_permission(auth.uid(),'finanzen.manage')) THEN RAISE EXCEPTION 'Keine Berechtigung zum Stornieren von Zahlungen'; END IF; UPDATE public.auftrag_zahlungsereignisse SET storniert = true, storniert_am = now(), storniert_by = auth.uid() WHERE id = _ereignis_id AND storniert = false; END; $fn$; GRANT EXECUTE ON FUNCTION public.storno_zahlung(uuid) TO authenticated;